   int BlackjackGame::calculate_hand_value(const std::vector<std::string>& hand) {
       int value = 0;
       int num_aces = 0;
       for (const auto& card : hand) {
           std::string rank = card.substr(0, card.length() - 1);
           if (isdigit(rank[0]) && rank.length() == 1) { // or just check if it's "2"-"9"
               value += std::stoi(rank);
           } else if (rank == "10" || rank == "J" || rank == "Q" || rank == "K") {
               value += 10;
           } else if (rank == "A") {
               value += 11;
               num_aces += 1;
           }
